local statusLabel = FarmRight:AddLabel({ Text = "Status: Menganggur " })
local worldLabel  = FarmRight:AddLabel({ Text = "Menara: mendeteksi... " })

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        if M.isSharedStallActive() then
            local remaining = math.max(0, math.ceil(M.getSharedStallUntil() - tick()))
            statusLabel:SetText("Status: Stalled " .. remaining .. "s ")
        elseif M.isClaimingWins() then
            statusLabel:SetText("Status: Mengklaim Kemenangan ")
        elseif M.isListening() then
            statusLabel:SetText("Status: Mendengarkan... ")
        elseif M.isAllCaptured() then
            statusLabel:SetText("Status: Siap! ")
        else
            statusLabel:SetText("Status: Belum disiapkan ")
        end
        worldLabel:SetText("Tower: " .. (M.getCurrentWorldName() or "not found") .. " ")
    end
end)

