-- FARM POSITION TAB
local SpotLeft  = Tabs.Spot:AddLeftGroupbox("Override Posisi ")
local SpotRight = Tabs.Spot:AddRightGroupbox("Tombol Simpan Cepat ")

local overrideLabel = SpotLeft:AddLabel({ Text = "Posisi Kustom: MATI " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "Tersimpan: tidak ada " })

SpotLeft:AddButton("Simpan Posisi Saat Ini ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="Kesalahan ", Description="Tidak ada karakter! ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="Kesalahan ", Description="Tidak ada HumanoidRootPart! ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="Posisi Tersimpan! ", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("Hapus Posisi Kustom ", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("Tersimpan: tidak ada ")
    Library:Notify({Title="Dihapus ", Description="Menggunakan titik tangkapan asli. ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

local keybindLabel = SpotRight:AddLabel({ Text = "Tombol Simpan Cepat: F " })

SpotRight:AddButton("Atur Tombol Simpan Cepat ", function()
